// Description: Discovers Nexus blob stores via the blobstores REST API.
// Description: Each blob store becomes a monitored instance with type as a grouping property.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"

if (!host || !user || !pass) {
    return 1
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

try {
    def url = new URL("${baseUrl}/service/rest/v1/blobstores")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Basic ${credentials}")
    conn.setRequestProperty("Accept", "application/json")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)

    if (conn.responseCode == 200) {
        def stores = new JsonSlurper().parseText(conn.inputStream.text)
        stores.each { store ->
            def name = store.name ?: "unknown"
            def type = store.type ?: "unknown"
            println "${name}##${name}##Blob store ${name} (${type})####auto.blobstore.type=${type}"
        }
    } else {
        System.err.println("Blob store discovery failed: HTTP ${conn.responseCode}")
        return 1
    }
} catch (Exception e) {
    System.err.println("Blob store discovery error: ${e.message}")
    return 1
}
return 0

