// Description: Collects per-blob-store metrics from the blobstores list and quota-status APIs.
// Description: Fetches the full blob store list, filters to this instance, then checks quota status.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"
def storeName = instanceProps.get("wildvalue")

def results = [
    "available": 0,
    "blob_count": 0,
    "total_size_bytes": 0,
    "available_space_bytes": 0,
    "used_percent": 0,
    "quota_violation": 0
]

if (!host || !user || !pass || !storeName) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def nexusGet(String path, String baseUrl, String credentials) {
    try {
        def url = new URL("${baseUrl}${path}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Basic ${credentials}")
        conn.setRequestProperty("Accept", "application/json")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)
        if (conn.responseCode == 200) {
            return new JsonSlurper().parseText(conn.inputStream.text)
        } else {
            System.err.println("Nexus API error: HTTP ${conn.responseCode} for ${path}")
        }
    } catch (Exception e) {
        System.err.println("Nexus API error for ${path}: ${e.message}")
    }
    return null
}

// Fetch blob store list and find this instance
def stores = nexusGet("/service/rest/v1/blobstores", baseUrl, credentials)
if (stores != null) {
    def store = stores.find { it.name == storeName }
    if (store) {
        results["available"] = (store.unavailable == true) ? 0 : 1
        results["blob_count"] = store.blobCount ?: 0
        results["total_size_bytes"] = store.totalSizeInBytes ?: 0
        results["available_space_bytes"] = store.availableSpaceInBytes ?: 0

        def totalSize = store.totalSizeInBytes ?: 0
        def availSpace = store.availableSpaceInBytes ?: 0
        def totalCapacity = totalSize + availSpace
        results["used_percent"] = (totalCapacity > 0) ? ((totalSize / totalCapacity) * 100).round(2) : 0
    }
}

// Fetch quota status for this store
def quotaStatus = nexusGet("/service/rest/v1/blobstores/${storeName}/quota-status", baseUrl, credentials)
if (quotaStatus != null) {
    results["quota_violation"] = quotaStatus.isViolation ? 1 : 0
}

results.each { k, v -> println("${k}:${v}") }
return 0
